import{_ as e,o as a,c as i,a2 as s}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Runs","description":"","frontmatter":{},"headers":[],"relativePath":"manual/runs.md","filePath":"manual/runs.md","lastUpdated":null}'),n={name:"manual/runs.md"};function r(l,t,o,h,d,p){return a(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="runs" tabindex="-1">Runs <a class="header-anchor" href="#runs" aria-label="Permalink to &quot;Runs&quot;">​</a></h1><p>A run is the operator&#39;s main unit of work in Autofac. It is one execution of a workflow, with its own context, steps, approvals, evidence, and audit trail.</p><h2 id="start-a-run-from-the-ui" tabindex="-1">Start a run from the UI <a class="header-anchor" href="#start-a-run-from-the-ui" aria-label="Permalink to &quot;Start a run from the UI&quot;">​</a></h2><ol><li>Open the web UI.</li><li>Go to Runs.</li><li>Choose a workflow or use the seeded sample in the quickstart stack.</li><li>Start the run.</li><li>Open the run detail page.</li></ol><p>The run detail view shows the BPMN diagram, step status, approval state, and run events.</p><h2 id="start-a-run-from-the-api" tabindex="-1">Start a run from the API <a class="header-anchor" href="#start-a-run-from-the-api" aria-label="Permalink to &quot;Start a run from the API&quot;">​</a></h2><p>Use <code>POST /api/runs</code> with the workflow id.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">API</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:8081</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">viewer-or-operator-token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/api/runs&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;workflowId&quot;:&quot;wf-first-run-sample&quot;}&#39;</span></span></code></pre></div><p>The API returns the new run id. Use that id for follow-up inspection.</p><h2 id="inspect-a-run" tabindex="-1">Inspect a run <a class="header-anchor" href="#inspect-a-run" aria-label="Permalink to &quot;Inspect a run&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/api/runs/&lt;run-id&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span></span></code></pre></div><p>Look at:</p><table tabindex="0"><thead><tr><th>Field</th><th>What it tells you</th></tr></thead><tbody><tr><td><code>status</code></td><td>Whether the run is active, blocked, completed, or failed.</td></tr><tr><td><code>currentStep</code></td><td>The workflow step currently holding the run.</td></tr><tr><td><code>pendingApprovals</code></td><td>Number of approval requests waiting for a decision.</td></tr><tr><td><code>riskLevel</code></td><td>The current workflow-level risk signal.</td></tr><tr><td><code>startedAt</code> / <code>completedAt</code></td><td>Runtime duration and completion state.</td></tr></tbody></table><h2 id="read-step-history" tabindex="-1">Read step history <a class="header-anchor" href="#read-step-history" aria-label="Permalink to &quot;Read step history&quot;">​</a></h2><p>Each step records status, type, timestamps, agent name, output, and policy decision data. When diagnosing a run, check the first step with a non-success status. The most useful details are usually:</p><ul><li>The step output.</li><li>The policy decision rationale.</li><li>Risk factors.</li><li>Tool constraints.</li><li>Audit events around the same timestamp.</li></ul><h2 id="understand-common-pauses" tabindex="-1">Understand common pauses <a class="header-anchor" href="#understand-common-pauses" aria-label="Permalink to &quot;Understand common pauses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pause</th><th>Cause</th><th>Operator action</th></tr></thead><tbody><tr><td>Approval</td><td>A BPMN approval task is waiting.</td><td>Review and approve, reject, or request changes.</td></tr><tr><td>Human question</td><td>An agent used <code>human.ask</code>.</td><td>Answer the question in the run conversation.</td></tr><tr><td>External event</td><td>A receive task or catch event is waiting.</td><td>Deliver the correlated webhook/event or inspect integration health.</td></tr><tr><td>Timer</td><td>A BPMN timer is active.</td><td>Wait, or verify timer configuration if it is unexpected.</td></tr></tbody></table><h2 id="cancel-or-recover" tabindex="-1">Cancel or recover <a class="header-anchor" href="#cancel-or-recover" aria-label="Permalink to &quot;Cancel or recover&quot;">​</a></h2><p>Operators can cancel or recover runs through the API and UI surfaces exposed by the product. Prefer recovery when a transient integration, model provider, or dispatch worker issue has been fixed. Prefer cancellation when the run is no longer desired or the underlying workflow definition is wrong.</p><p>Before recovery, inspect:</p><ul><li>Whether the failed step is idempotent.</li><li>Whether a connector already created an external artifact, branch, issue, or pull request.</li><li>Whether the run context still matches the current external state.</li></ul><h2 id="operational-checklist" tabindex="-1">Operational checklist <a class="header-anchor" href="#operational-checklist" aria-label="Permalink to &quot;Operational checklist&quot;">​</a></h2><ul><li>Confirm the run is on the expected workflow version.</li><li>Confirm the initiator and trigger context are expected.</li><li>Check pending approvals before diagnosing a run as stuck.</li><li>Review tool and policy decisions before retrying a failed agent step.</li><li>Download the evidence pack before deleting artifacts or tearing down test data.</li></ul>`,24)])])}const k=e(n,[["render",r]]);export{u as __pageData,k as default};
